settings.custom_liquid:
{% assign collection_handle = "pochettes-bulles" %}
{% assign products = collections[collection_handle].products %}

<style>
  table {
    width: 100%;
    border-collapse: collapse;
    margin-bottom: 20px;
    font-family: Arial, sans-serif;
  }
  thead tr {
    background-color: #f0f0f0;
  }
  th, td {
    border: 1px solid #ccc;
border-left: 0px;
border-right: 0px;
    padding: 12px;
    text-align: center;
  }
  th {
    font-weight: bold;
    font-size: 14px;
  }
  td {
    font-size: 14px;
  }
  .cart-button {
    background: none;
    border: none;
    cursor: pointer;
  }
  .cart-button img {
    width: 24px;
    height: 24px;
  }
  @media (max-width: 768px) {
    .responsive-table {
      display: flex;
      flex-direction: column;
    }
    .responsive-row {
      display: flex;
      flex-wrap: wrap;
      border: 1px solid #ccc;
      margin-bottom: 10px;
    }
    .responsive-cell {
      flex: 1;
      padding: 12px;
      border: none;
      text-align: left;
    }
    .responsive-cell img {
      max-width: 100%;
      height: auto;
    }
    .description-cell {
      display: none;
    }
  }
</style>

<table class="responsive-table">
  <thead>
    <tr>
      <th></th>
      <th>Réf.</th>
      <th class="description-cell">Description</th>
      <th>Prix</th>
      <th></th>
    </tr>
  </thead>
  <tbody>
    {% for product in products %}
    <tr class="responsive-row">
      <td class="responsive-cell" data-label="Image">
        <img src="{{ product.featured_image | img_url: '50x50' }}" alt="{{ product.title }}">
      </td>
      <td class="responsive-cell" data-label="Réf.">
        <a href="{{ product.url }}" style="text-decoration: none; color: #333;">{{ product.title }}</a>
      </td>
      <td class="responsive-cell description-cell" data-label="Description">{{ product.description | strip_html | truncate: 100 }}</td>
      <td class="responsive-cell" data-label="Prix">{{ product.price | money }}</td>
      <td class="responsive-cell" data-label="Ajouter au panier">
        <form action="/cart/add" method="post" style="text-align: center;">
          <input type="hidden" name="id" value="{{ product.variants.first.id }}">
          <button type="submit" class="cart-button">
            <img src="https://cdn.shopify.com/s/files/1/0937/2188/7061/files/shopping-cart.png?v=1741003707" alt="Ajouter au panier">
          </button>
        </form>
      </td>
    </tr>
    {% endfor %}
  </tbody>
</table>
